import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar'; 
import Footer from './components/Footer/Footer';
import Hero from './components/Home/Hero';
import Features from './components/Home/Features';
import JobListContainer from './features/eksplorasi/JobListContainer';
import FavoriteListContainer from './features/eksplorasi/FavoriteListContainer';
import Login from './components/auth/Login'; 
import Register from './components/auth/Register';

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    const [activeMenu, setActiveMenu] = useState('eksplorasi');

    return (
        <Router>
            <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', background: '#080402', color: '#fff' }}>
                <Navbar isAuthenticated={isAuthenticated} activeMenu={activeMenu} setActiveMenu={setActiveMenu} />

                <main style={{ flex: 1 }}>
                    <Routes>
                        <Route path="/" element={
                            <>
                                {/* Halaman Utama / Guest Landing Page */}
                                {!isAuthenticated && (
                                    <>
                                        <Hero />
                                        <Features />
                                    </>
                                )}

                                <div style={{ padding: '40px 80px' }}>
                                    {activeMenu === 'eksplorasi' && <JobListContainer />}
                                    {activeMenu === 'favorit' && (isAuthenticated ? <FavoriteListContainer /> : <Navigate to="/login" />)}
                                </div>
                            </>
                        } />
                        <Route path="/login" element={<Login onLoginSuccess={() => setIsAuthenticated(true)} />} />
                        <Route path="/register" element={<Register />} />
                    </Routes>
                </main>

                <Footer />
            </div>
        </Router>
    );
};

export default App;
